4	export function createInternalModuleRegistry(basedir: string) {
5	  const moduleList = ["bun", "node", "thirdparty", "internal"]
6	    .flatMap(dir => readdirRecursive(path.join(basedir, dir)))
7	    .filter(file => file.endsWith(".js") || (file.endsWith(".ts") && !file.endsWith(".d.ts")))
8	    .map(file => file.slice(basedir.length + 1))
9	    .map(x => x.replaceAll("\\", "/"))
10	    .sort();
11	
12	  // Create the Internal Module Registry
13	  const internalRegistry = new Map();
14	  for (let i = 0; i < moduleList.length; i++) {
15	    const prefix = moduleList[i].startsWith("node/")
16	      ? "node:"
17	      : moduleList[i].startsWith("bun:")
18	        ? "bun:"
19	        : moduleList[i].startsWith("internal/")
20	          ? "internal/"
21	          : undefined;
22	    if (prefix) {
23	      const id = prefix + moduleList[i].slice(prefix.length).replaceAll(".", "/").slice(0, -3);
24	      internalRegistry.set(id, i);
25	    }
26	  }
27	
28	  moduleList.push("internal-for-testing.ts");
29	  internalRegistry.set("bun:internal-for-testing", moduleList.length - 1);
30	
31	  let nextNativeModuleId = 0;
32	  const nativeModuleIds: Record<string, number> = {};
33	  const nativeModuleEnums: Record<string, string> = {};
34	  const nativeModuleEnumToId: Record<string, number> = {};
35	
36	  // Native Module registry
37	  const nativeModuleH = fs.readFileSync(path.join(basedir, "../bun.js/modules/_NativeModule.h"), "utf8");
38	  for (const [_, idString, enumValue] of nativeModuleH.matchAll(/macro\((.*?),(.*?)\)/g)) {
39	    const processedIdString = JSON.parse(idString.trim().replace(/_s$/, ""));
40	    const processedEnumValue = enumValue.trim();
41	    const processedNumericId = nextNativeModuleId++;
42	    nativeModuleIds[processedIdString] = processedNumericId;
43	    nativeModuleEnums[processedIdString] = processedEnumValue;
44	    nativeModuleEnumToId[processedEnumValue] = processedNumericId;
45	  }
46	
47	  const nativeStartIndex = moduleList.length;
48	
49	  for (const [id] of Object.entries(nativeModuleIds)) {
50	    moduleList.push(id);
51	    internalRegistry.set(id, moduleList.length - 1);
52	  }
53	
54	  if (nextNativeModuleId === 0) {
55	    throw new Error(
56	      "Could not find BUN_FOREACH_ESM_AND_CJS_NATIVE_MODULE in _NativeModule.h. Knowing native module IDs is a part of the codegen process.",
57	    );
58	  }
59	
60	  function codegenRequireId(id: string) {
61	    return `(__intrinsic__getInternalField(__intrinsic__internalModuleRegistry, ${id}) || __intrinsic__createInternalModuleById(${id}))`;
62	  }
63	
64	  const requireTransformer = (specifier: string, from: string) => {
65	    const directMatch = internalRegistry.get(specifier);
66	    if (directMatch) return codegenRequireId(`${directMatch}/*${specifier}*/`);
67	
68	    const relativeMatch =
69	      resolveSyncOrNull(specifier, path.join(basedir, path.dirname(from))) ?? resolveSyncOrNull(specifier, basedir);
70	
71	    const suffix =
72	      'Only files in "src/js" besides "src/js/builtins" can be imported here. Note that the "node:" or "bun:" prefix is required here.';
73	
74	    if (relativeMatch) {
75	      const found = moduleList.indexOf(path.relative(basedir, relativeMatch).replaceAll("\\", "/"));
76	      if (found === -1) {
77	        throw new Error(
78	          `Builtin Bundler: "${specifier}" cannot be imported from "${from}" because it doesn't get a module ID. ${suffix}`,
79	        );
80	      }
81	      return codegenRequireId(`${found}/*${path.relative(basedir, relativeMatch)}*/`);
82	    }
83	
84	    throw new Error(`Builtin Bundler: Could not resolve "${specifier}" in "${from}". ${suffix}`);
85	  };
86	
87	  return {
88	    requireTransformer,
89	    nativeModuleIds,
90	    nativeModuleEnums,
91	    nativeModuleEnumToId,
92	    internalRegistry,
93	    moduleList,
94	    nativeStartIndex,
95	  } as const;
96	}
