1	const HashMapPool = struct {
2	    const HashMap = std.HashMap(u64, void, IdentityContext, 80);
3	    const LinkedList = bun.deprecated.SinglyLinkedList(HashMap);
4	    threadlocal var list: LinkedList = undefined;
5	    threadlocal var loaded: bool = false;
6	
7	    pub fn get(_: std.mem.Allocator) *LinkedList.Node {
8	        if (loaded) {
9	            if (list.popFirst()) |node| {
10	                node.data.clearRetainingCapacity();
11	                return node;
12	            }
13	        }
14	
15	        const new_node = default_allocator.create(LinkedList.Node) catch unreachable;
16	        new_node.* = LinkedList.Node{ .data = HashMap.initContext(default_allocator, IdentityContext{}) };
17	        return new_node;
18	    }
19	
20	    pub fn release(node: *LinkedList.Node) void {
21	        if (loaded) {
22	            list.prepend(node);
23	            return;
24	        }
25	
26	        list = LinkedList{ .first = node };
27	        loaded = true;
28	    }
29	};
