465	                this.builder.append(.lchar, '}');
466	            },
467	            .number, .str => {
468	                this.builder.ensureUnusedCapacity(iter.len * ": ".len);
469	
470	                var first = true;
471	                while (try iter.next()) |prop_name| {
472	                    if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) {
473	                        continue;
474	                    }
475	
476	                    if (!first) {
477	                        this.newline();
478	                    }
479	                    first = false;
480	
481	                    this.appendString(prop_name);
482	                    this.builder.append(.latin1, ": ");
