            if (std.math.isNegativeInf(num)) {
                this.builder.append(.latin1, "-Infinity");
            } else if (std.math.isInf(num)) {
                this.builder.append(.latin1, "Infinity");
            } else if (std.math.isNan(num)) {
                this.builder.append(.latin1, "NaN");
            } else {
                this.builder.append(.double, num);
            }
            return;
        }

