1	/**
2	 * Bun.js runtime APIs
3	 *
4	 * @example
5	 *
6	 * ```js
7	 * import {file} from 'bun';
8	 *
9	 * // Log the file to the console
10	 * const input = await file('/path/to/file.txt').text();
11	 * console.log(input);
12	 * ```
13	 *
14	 * This module aliases `globalThis.Bun`.
15	 */
16	declare module "bun" {
17	  type PathLike = string | NodeJS.TypedArray | ArrayBufferLike | URL;
18	  type ArrayBufferView<TArrayBuffer extends ArrayBufferLike = ArrayBufferLike> =
19	    | NodeJS.TypedArray<TArrayBuffer>
20	    | DataView<TArrayBuffer>;
21	  type BufferSource = NodeJS.TypedArray<ArrayBufferLike> | DataView<ArrayBufferLike> | ArrayBufferLike;
22	  type StringOrBuffer = string | NodeJS.TypedArray | ArrayBufferLike;
23	  type XMLHttpRequestBodyInit = Blob | BufferSource | FormData | URLSearchParams | string;
24	  type ReadableStreamController<T> = ReadableStreamDefaultController<T>;
25	  type ReadableStreamDefaultReadResult<T> =
26	    | ReadableStreamDefaultReadValueResult<T>
27	    | ReadableStreamDefaultReadDoneResult;
28	  type ReadableStreamReader<T> = ReadableStreamDefaultReader<T>;
29	  type Transferable = ArrayBuffer | MessagePort;
30	  type MessageEventSource = Bun.__internal.UseLibDomIfAvailable<"MessageEventSource", undefined>;
31	  type Encoding = "utf-8" | "windows-1252" | "utf-16";
32	  type UncaughtExceptionOrigin = "uncaughtException" | "unhandledRejection";
33	  type MultipleResolveType = "resolve" | "reject";
34	  type BeforeExitListener = (code: number) => void;
35	  type DisconnectListener = () => void;
36	  type ExitListener = (code: number) => void;
37	  type RejectionHandledListener = (promise: Promise<unknown>) => void;
38	  type FormDataEntryValue = File | string;
39	  type WarningListener = (warning: Error) => void;
40	  type MessageListener = (message: unknown, sendHandle: unknown) => void;
41	  type SignalsListener = (signal: NodeJS.Signals) => void;
42	  type BlobPart = string | Blob | BufferSource;
43	  type TimerHandler = (...args: any[]) => void;
44	  type DOMHighResTimeStamp = number;
45	  type EventListenerOrEventListenerObject = EventListener | EventListenerObject;
46	  type BlobOrStringOrBuffer = string | NodeJS.TypedArray | ArrayBufferLike | Blob;
47	  type MaybePromise<T> = T | Promise<T>;
48	
49	  namespace __internal {
50	    type LibDomIsLoaded = typeof globalThis extends { onabort: any } ? true : false;
51	
52	    /**
53	     * Helper type for avoiding conflicts in types.
54	     *
55	     * Uses the lib.dom.d.ts definition if it exists, otherwise defines it locally.
56	     *
57	     * This is to avoid type conflicts between lib.dom.d.ts and \@types/bun.
58	     *
59	     * Unfortunately some symbols cannot be defined when both Bun types and lib.dom.d.ts types are loaded,
60	     * and since we can't redeclare the symbol in a way that satisfies both, we need to fallback
61	     * to the type that lib.dom.d.ts provides.
62	     */
63	    type UseLibDomIfAvailable<GlobalThisKeyName extends PropertyKey, Otherwise> =
64	      // `onabort` is defined in lib.dom.d.ts, so we can check to see if lib dom is loaded by checking if `onabort` is defined
65	      LibDomIsLoaded extends true
66	        ? typeof globalThis extends { [K in GlobalThisKeyName]: infer T } // if it is loaded, infer it from `globalThis` and use that value
67	          ? T
68	          : Otherwise // Not defined in lib dom (or anywhere else), so no conflict. We can safely use our own definition
69	        : Otherwise; // Lib dom not loaded anyway, so no conflict. We can safely use our own definition
70	
71	    /**
72	     * Like Omit, but correctly distributes over unions. Most useful for removing
73	     * properties from union options objects, like {@link Bun.SQL.Options}
74	     *
75	     * @example
76	     * ```ts
77	     * type X = Bun.DistributedOmit<{type?: 'a', url?: string} | {type?: 'b', flag?: boolean}, "url">
78	     * // `{type?: 'a'} | {type?: 'b', flag?: boolean}` (Omit applied to each union item instead of entire type)
79	     *
80	     * type X = Omit<{type?: 'a', url?: string} | {type?: 'b', flag?: boolean}, "url">;
81	     * // `{type?: "a" | "b" | undefined}` (Missing `flag` property and no longer a union)
82	     * ```
83	     */
84	    type DistributedOmit<T, K extends PropertyKey> = T extends T ? Omit<T, K> : never;
