1349	pub fn getEmbeddedFiles(globalThis: *jsc.JSGlobalObject, _: *jsc.JSObject) bun.JSError!jsc.JSValue {
1350	    const vm = globalThis.bunVM();
1351	    const graph = vm.standalone_module_graph orelse return try jsc.JSValue.createEmptyArray(globalThis, 0);
1352	
1353	    const unsorted_files = graph.files.values();
1354	    var sort_indices = bun.handleOom(std.array_list.Managed(u32).initCapacity(bun.default_allocator, unsorted_files.len));
1355	    defer sort_indices.deinit();
1356	    for (0..unsorted_files.len) |index| {
1357	        // Some % of people using `bun build --compile` want to obscure the source code
1358	        // We don't really do that right now, but exposing the output source
1359	        // code here as an easily accessible Blob is even worse for them.
1360	        // So let's omit any source code files from the list.
1361	        if (!unsorted_files[index].appearsInEmbeddedFilesArray()) continue;
1362	        sort_indices.appendAssumeCapacity(@intCast(index));
1363	    }
1364	
1365	    var i: u32 = 0;
1366	    var array = try jsc.JSValue.createEmptyArray(globalThis, sort_indices.items.len);
1367	    std.mem.sort(u32, sort_indices.items, unsorted_files, bun.StandaloneModuleGraph.File.lessThanByIndex);
1368	    for (sort_indices.items) |index| {
1369	        const file = &unsorted_files[index];
1370	        // We call .dupe() on this to ensure that we don't return a blob that might get freed later.
1371	        const input_blob = file.blob(globalThis);
1372	        const blob = jsc.WebCore.Blob.new(input_blob.dupeWithContentType(true));

1	const HashMapPool = struct {
2	    const HashMap = std.HashMap(u64, void, IdentityContext, 80);
3	    const LinkedList = bun.deprecated.SinglyLinkedList(HashMap);
4	    threadlocal var list: LinkedList = undefined;
5	    threadlocal var loaded: bool = false;
6	
7	    pub fn get(_: std.mem.Allocator) *LinkedList.Node {
8	        if (loaded) {
9	            if (list.popFirst()) |node| {
10	                node.data.clearRetainingCapacity();
11	                return node;
12	            }
13	        }
14	
15	        const new_node = default_allocator.create(LinkedList.Node) catch unreachable;
16	        new_node.* = LinkedList.Node{ .data = HashMap.initContext(default_allocator, IdentityContext{}) };
17	        return new_node;
18	    }
19	
20	    pub fn release(node: *LinkedList.Node) void {
21	        if (loaded) {
22	            list.prepend(node);
23	            return;
24	        }
25	
26	        list = LinkedList{ .first = node };
27	        loaded = true;
28	    }
29	};
