1	pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
2	    const object = JSValue.createEmptyObject(globalThis, 2);
3	    object.put(
4	        globalThis,
5	        ZigString.static("parse"),
6	        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
7	    );
8	    object.put(
9	        globalThis,
10	        ZigString.static("stringify"),
11	        jsc.JSFunction.create(globalThis, "stringify", stringify, 3, .{}),
12	    );
13	    return object;
14	}
15	
16	pub fn stringify(
17	    global: *jsc.JSGlobalObject,
18	    callFrame: *jsc.CallFrame,
19	) bun.JSError!jsc.JSValue {
20	    const value, const replacer, const space_value = callFrame.argumentsAsArray(3);
21	
22	    value.ensureStillAlive();
23	
24	    if (value.isUndefined() or value.isSymbol() or value.isFunction()) {
25	        return .js_undefined;
26	    }
27	
28	    if (!replacer.isUndefinedOrNull()) {
29	        return global.throw("JSON5.stringify does not support the replacer argument", .{});
30	    }
31	
32	    var stringifier: Stringifier = try .init(global, space_value);
33	    defer stringifier.deinit();
34	
35	    stringifier.stringifyValue(global, value) catch |err| return switch (err) {
36	        error.OutOfMemory, error.JSError, error.JSTerminated => |js_err| js_err,
37	        error.StackOverflow => global.throwStackOverflow(),
38	    };
39	
40	    return stringifier.builder.toString(global);
41	}
42	
43	pub fn parse(
44	    global: *jsc.JSGlobalObject,
45	    callFrame: *jsc.CallFrame,
46	) bun.JSError!jsc.JSValue {
47	    var arena: bun.ArenaAllocator = .init(bun.default_allocator);
48	    defer arena.deinit();
49	    const allocator = arena.allocator();
50	
51	    var ast_memory_allocator = bun.handleOom(allocator.create(ast.ASTMemoryAllocator));
52	    var ast_scope = ast_memory_allocator.enter(allocator);
53	    defer ast_scope.exit();
54	
55	    const input_value = callFrame.argument(0);
56	
57	    if (input_value.isEmptyOrUndefinedOrNull()) {
58	        return global.throwInvalidArguments("Expected a string to parse", .{});
59	    }
60	
61	    const input: jsc.Node.BlobOrStringOrBuffer =
62	        try jsc.Node.BlobOrStringOrBuffer.fromJS(global, allocator, input_value) orelse input: {
63	            var str = try input_value.toBunString(global);
64	            defer str.deref();
65	            break :input .{ .string_or_buffer = .{ .string = str.toSlice(allocator) } };
66	        };
67	    defer input.deinit();
68	
69	    var log = logger.Log.init(bun.default_allocator);
70	    defer log.deinit();
71	
72	    const source = &logger.Source.initPathString("input.json5", input.slice());
73	
74	    const root = json5.JSON5Parser.parse(source, &log, allocator) catch |err| return switch (err) {
75	        error.OutOfMemory => |oom| oom,
76	        error.StackOverflow => global.throwStackOverflow(),
77	        else => {
78	            if (log.msgs.items.len > 0) {
79	                const first_msg = log.msgs.items[0];
80	                return global.throwValue(global.createSyntaxErrorInstance(
81	                    "JSON5 Parse error: {s}",
82	                    .{first_msg.data.text},
83	                ));
84	            }
85	            return global.throwValue(global.createSyntaxErrorInstance(
86	                "JSON5 Parse error: Unable to parse JSON5 string",
87	                .{},
88	            ));
89	        },
90	    };
91	
92	    return exprToJS(root, global);
93	}
94	
95	const Stringifier = struct {
96	    stack_check: bun.StackCheck,
97	    builder: wtf.StringBuilder,
98	    indent: usize,
99	    space: Space,
100	    visiting: std.AutoHashMapUnmanaged(JSValue, void),
101	    allocator: std.mem.Allocator,
102	
103	    const StringifyError = bun.JSError || bun.StackOverflow;
104	
105	    const Space = union(enum) {
106	        minified,
107	        number: u32,
108	        str: bun.String,
109	
110	        pub fn init(global: *jsc.JSGlobalObject, space_value: JSValue) bun.JSError!Space {
111	            const space = try space_value.unwrapBoxedPrimitive(global);
112	            if (space.isNumber()) {
113	                // Clamp on the float to match the spec's min(10, ToIntegerOrInfinity(space)).
114	                // toInt32() wraps large values and Infinity to 0, which is wrong.
115	                const num_f = space.asNumber();
116	                if (!(num_f >= 1)) return .minified; // handles NaN, -Infinity, 0, negatives
117	                return .{ .number = if (num_f > 10) 10 else @intFromFloat(num_f) };
118	            }
119	            if (space.isString()) {
120	                const str = try space.toBunString(global);
121	                if (str.length() == 0) {
122	                    str.deref();
123	                    return .minified;
124	                }
125	                return .{ .str = str };
126	            }
127	            return .minified;
128	        }
129	
130	        pub fn deinit(this: *const Space) void {
131	            switch (this.*) {
132	                .str => |str| str.deref(),
133	                .minified, .number => {},
134	            }
135	        }
136	    };
137	
138	    pub fn init(global: *jsc.JSGlobalObject, space_value: JSValue) bun.JSError!Stringifier {
139	        return .{
140	            .stack_check = .init(),
141	            .builder = .init(),
142	            .indent = 0,
143	            .space = try Space.init(global, space_value),
144	            .visiting = .empty,
145	            .allocator = bun.default_allocator,
146	        };
147	    }
148	
149	    pub fn deinit(this: *Stringifier) void {
150	        this.builder.deinit();
151	        this.space.deinit();
152	        this.visiting.deinit(this.allocator);
153	    }
154	
155	    pub fn stringifyValue(this: *Stringifier, global: *jsc.JSGlobalObject, value: JSValue) StringifyError!void {
156	        if (!this.stack_check.isSafeToRecurse()) {
157	            return error.StackOverflow;
158	        }
159	
160	        const unwrapped = try value.unwrapBoxedPrimitive(global);
161	
162	        if (unwrapped.isNull()) {
163	            this.builder.append(.latin1, "null");
164	            return;
165	        }
166	
167	        if (unwrapped.isNumber()) {
168	            if (unwrapped.isInt32()) {
169	                this.builder.append(.int, unwrapped.asInt32());
170	                return;
171	            }
172	            const num = unwrapped.asNumber();
173	            if (std.math.isNegativeInf(num)) {
174	                this.builder.append(.latin1, "-Infinity");
175	            } else if (std.math.isInf(num)) {
176	                this.builder.append(.latin1, "Infinity");
177	            } else if (std.math.isNan(num)) {
178	                this.builder.append(.latin1, "NaN");
179	            } else {
180	                this.builder.append(.double, num);
181	            }
182	            return;
183	        }
184	
185	        if (unwrapped.isBigInt()) {
186	            return global.throw("JSON5.stringify cannot serialize BigInt", .{});
187	        }
188	
189	        if (unwrapped.isBoolean()) {
190	            this.builder.append(.latin1, if (unwrapped.asBoolean()) "true" else "false");
191	            return;
192	        }
193	
194	        if (unwrapped.isString()) {
195	            const str = try unwrapped.toBunString(global);
196	            defer str.deref();
197	            this.appendQuotedString(str);
198	            return;
199	        }
200	
201	        // Object or array вҖ” check for circular references
202	        const gop = try this.visiting.getOrPut(this.allocator, unwrapped);
203	        if (gop.found_existing) {
204	            return global.throw("Converting circular structure to JSON5", .{});
205	        }
206	        defer _ = this.visiting.remove(unwrapped);
207	
208	        if (unwrapped.isArray()) {
209	            try this.stringifyArray(global, unwrapped);
210	        } else {
211	            try this.stringifyObject(global, unwrapped);
212	        }
213	    }
214	
215	    fn stringifyArray(this: *Stringifier, global: *jsc.JSGlobalObject, value: JSValue) StringifyError!void {
216	        var iter = try value.arrayIterator(global);
217	
218	        if (iter.len == 0) {
219	            this.builder.append(.latin1, "[]");
220	            return;
221	        }
222	
223	        this.builder.append(.lchar, '[');
224	
225	        switch (this.space) {
226	            .minified => {
227	                var first = true;
228	                while (try iter.next()) |item| {
229	                    if (!first) this.builder.append(.lchar, ',');
230	                    first = false;
231	                    if (item.isUndefined() or item.isSymbol() or item.isFunction()) {
232	                        this.builder.append(.latin1, "null");
233	                    } else {
234	                        try this.stringifyValue(global, item);
235	                    }
236	                }
237	            },
238	            .number, .str => {
239	                this.indent += 1;
240	                var first = true;
241	                while (try iter.next()) |item| {
242	                    if (!first) this.builder.append(.lchar, ',');
243	                    first = false;
244	                    this.newline();
245	                    if (item.isUndefined() or item.isSymbol() or item.isFunction()) {
246	                        this.builder.append(.latin1, "null");
247	                    } else {
248	                        try this.stringifyValue(global, item);
249	                    }
250	                }
251	                // Trailing comma
252	                this.builder.append(.lchar, ',');
253	                this.indent -= 1;
254	                this.newline();
255	            },
