pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn parse(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callframe.argument(0);
    if (input_value.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
    }

    var input_slice = try input_value.toSlice(globalThis, bun.default_allocator);
    defer input_slice.deinit();

    return parseINI(globalThis, input_slice.slice());
}

fn parseINI(globalThis: *jsc.JSGlobalObject, input: []const u8) bun.JSError!jsc.JSValue {
    const result = JSValue.createEmptyObject(globalThis, 0);
    result.protect();
    defer result.unprotect();

    var current_section = result;

    var iter = std.mem.splitScalar(u8, input, '\n');
    while (iter.next()) |line_raw| {
        const line_no_cr = if (line_raw.len > 0 and line_raw[line_raw.len - 1] == '\r')
            line_raw[0 .. line_raw.len - 1]
        else
            line_raw;

        const line = bun.strings.trim(line_no_cr, " \t");

        // Skip empty lines and comment lines
        if (line.len == 0 or line[0] == ';' or line[0] == '#') continue;

        // Section header: [section]
        if (line[0] == '[') {
            const close = std.mem.indexOfScalar(u8, line, ']') orelse continue;
            const section_name = bun.strings.trim(line[1..close], " \t");
            if (section_name.len == 0) continue;

            // Check if section already exists on the root object
            var name_str = bun.String.createUTF8(section_name);
            defer name_str.deref();

            const existing = result.getWithString(globalThis, &name_str);
            if (existing != .zero and existing != .js_undefined and existing.isObject()) {
                current_section = existing;
            } else {
                const section_obj = JSValue.createEmptyObject(globalThis, 0);
                section_obj.protect();
                defer section_obj.unprotect();
                try result.putMayBeIndex(globalThis, &name_str, section_obj);
                current_section = section_obj;
            }
            continue;
        }

        // Key=value pair
        const eq_idx = std.mem.indexOfScalar(u8, line, '=');
        const key_raw = if (eq_idx) |idx| bun.strings.trim(line[0..idx], " \t") else line;
        if (key_raw.len == 0) continue;

        const value_js = if (eq_idx) |idx| blk: {
            if (idx + 1 < line.len) {
                const val_raw = bun.strings.trim(line[idx + 1 ..], " \t");
                break :blk parseValue(globalThis, val_raw);
            }
            // key= with nothing after means empty string
            break :blk try bun.String.createUTF8ForJS(globalThis, "");
        } else
            // key with no = means true
            JSValue.jsBoolean(true);

        var key_str = bun.String.createUTF8(key_raw);
        defer key_str.deref();
        try current_section.putMayBeIndex(globalThis, &key_str, value_js);
    }

    return result;
}

fn parseValue(globalThis: *jsc.JSGlobalObject, raw: []const u8) jsc.JSValue {
    if (raw.len == 0) {
        return try_create_str: {
            break :try_create_str bun.String.createUTF8ForJS(globalThis, "") catch return .js_undefined;
        };
    }

    // Handle inline comments: strip text after unquoted ; or #
    const effective = stripInlineComment(raw);

    // Handle quoted strings (single or double quotes)
    if (effective.len >= 2) {
        if ((effective[0] == '"' and effective[effective.len - 1] == '"') or
            (effective[0] == '\'' and effective[effective.len - 1] == '\''))
        {
            const inner = effective[1 .. effective.len - 1];
            return bun.String.createUTF8ForJS(globalThis, inner) catch return .js_undefined;
        }
    }

    // Boolean values
    if (bun.strings.eqlCaseInsensitiveASCII(effective, "true", true))
        return JSValue.jsBoolean(true);
    if (bun.strings.eqlCaseInsensitiveASCII(effective, "false", true))
        return JSValue.jsBoolean(false);

    // Null
    if (bun.strings.eqlCaseInsensitiveASCII(effective, "null", true))
        return .null;

    // Try to parse as number
    if (parseNumber(effective)) |num| {
        return JSValue.jsNumber(num);
    }

    // Default: string value
    return bun.String.createUTF8ForJS(globalThis, effective) catch return .js_undefined;
}

fn stripInlineComment(raw: []const u8) []const u8 {
    // Don't strip from quoted strings
    if (raw.len >= 2 and (raw[0] == '"' or raw[0] == '\'')) return raw;

    var i: usize = 0;
    while (i < raw.len) : (i += 1) {
        if (raw[i] == ';' or raw[i] == '#') {
            // Only treat as comment if preceded by whitespace (or at start)
            if (i == 0 or raw[i - 1] == ' ' or raw[i - 1] == '\t') {
                return bun.strings.trim(raw[0..i], " \t");
            }
        }
    }
    return raw;
}

fn parseNumber(s: []const u8) ?f64 {
    if (s.len == 0) return null;

    // Check for hex
    if (s.len > 2 and s[0] == '0' and (s[1] == 'x' or s[1] == 'X')) {
        var val: u64 = 0;
        for (s[2..]) |c| {
            const digit: u64 = switch (c) {
                '0'...'9' => c - '0',
                'a'...'f' => c - 'a' + 10,
                'A'...'F' => c - 'A' + 10,
                else => return null,
            };
            val = val *% 16 +% digit;
        }
        return @floatFromInt(val);
    }

    // Parse as float
    return std.fmt.parseFloat(f64, s) catch return null;
}

pub fn stringify(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const value = callframe.argument(0);

    if (value.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }

    if (!value.isObject()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }

    var builder: wtf.StringBuilder = .init();
    defer builder.deinit();

    // First pass: emit top-level key-value pairs (non-object values)
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            globalThis,
            try value.toObject(globalThis),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            const prop_value = iter.value;
            // Skip nested objects (they become sections)
            if (prop_value.isObject() and !prop_value.isNull() and !prop_value.isArray()) continue;

            appendKey(&builder, prop_name);
            builder.append(.latin1, " = ");
            try appendValue(&builder, globalThis, prop_value);
            builder.append(.lchar, '\n');
        }
    }

    // Second pass: emit sections for nested objects
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            globalThis,
            try value.toObject(globalThis),
        );
        defer iter.deinit();

        var has_top_level = false;
        // Check if we wrote any top-level keys (for blank line separator)
        {
            var check_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
                globalThis,
                try value.toObject(globalThis),
            );
            defer check_iter.deinit();
            while (try check_iter.next()) |_| {
                const v = check_iter.value;
                if (!v.isObject() or v.isNull() or v.isArray()) {
                    has_top_= true;
                    break;
                }
            }
        }
        _ = has_top_level;

        var first_section = true;
        while (try iter.next()) |prop_name| {
            const prop_value = iter.value;
            if (!prop_value.isObject() or prop_value.isNull() or prop_value.isArray()) continue;

            // Add blank line before sections (unless it's the very first output)
            if (!first_section or has_top_) {
                builder.append(.lchar, '\n');
            }
            first_section = false;

            builder.append(.lchar, '[');
            appendKey(&builder, prop_name);
            builder.append(.latin1, "]\n");

            // Emit section properties
            var section_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
                globalThis,
                try prop_value.toObject(globalThis),
            );
            defer section_iter.deinit();

            while (try section_iter.next()) |section_prop_name| {
                appendKey(&builder, section_prop_name);
                builder.append(.latin1, " = ");
                try appendValue(&builder, globalThis, section_iter.value);
                builder.append(.lchar, '\n');
            }
        }
    }

    return builder.toString(globalThis);
}

fn appendKey(builder: *wtf.StringBuilder, name: bun.String) void {
    builder.append(.string, name);
}

fn appendValue(builder: *wtf.StringBuilder, globalThis: *jsc.JSGlobalObject, value: jsc.JSValue) bun.JSError!void {
    if (value.isNull()) {
        builder.append(.latin1, "null");
        return;
    }

    if (value.isBoolean()) {
        builder.append(.latin1, if (value.asBoolean()) "true" else "false");
        return;
    }

    if (value.isNumber()) {
        if (value.isInt32()) {
            builder.append(.int, value.asInt32());
        } else {
            builder.append(.double, value.asNumber());
        }
        return;
    }

    if (value.isString()) {
        const str = try value.toBunString(globalThis);
        defer str.deref();
        // Check if the string needs quoting
        if (needsQuoting(str)) {
            builder.append(.lchar, '"');
            builder.append(.string, str);
            builder.append(.lchar, '"');
        } else {
            builder.append(.string, str);
        }
        return;
    }

    if (value.isArray()) {
        // Arrays are not natively supported in INI, stringify as comma-separated
        var arr_iter = try value.arrayIterator(globalThis);
        var first = true;
        while (try arr_iter.next()) |item| {
            if (!first) builder.append(.latin1, ", ");
            first = false;
            try appendValue(builder, globalThis, item);
        }
        return;
    }

    // For other types, convert to string
    const str = try value.toBunString(globalThis);
    defer str.deref();
    builder.append(.string, str);
}

fn needsQuoting(str: bun.String) bool {
    const len = str.length();
    if (len == 0) return true;

    for (0..len) |i| {
        const c = str.charAt(i);
        switch (c) {
            ';', '#', '=', '"', '\'', '\n', '\r', '\t' => return true,
            else => {},
        }
    }

    // Check if it looks like a keyword or number that should be quoted to preserve as string
    // We don't quote here since stringify produces machine-readable output
    return false;
}

