                };
                reader.list = .{ .items = reader.list.items };
                reader.list.capacity = reader.list.items.len;
                reader.list_ptr = &reader.list;

                var array_buffer = jsc.ArrayBuffer.fromBytes(reader.list.items, .Uint8Array);
