import { INI } from "bun";
import { describe, expect, test } from "bun:test";

describe("Bun.INI", () => {
  test("is accessible as Bun.INI", () => {
    expect(Bun.INI).toBeDefined();
    expect(typeof Bun.INI.parse).toBe("function");
    expect(typeof Bun.INI.stringify).toBe("function");
  });

  test("is accessible as named import", () => {
    expect(INI).toBeDefined();
    expect(typeof INI.parse).toBe("function");
    expect(typeof INI.stringify).toBe("function");
  });

  describe("parse", () => {
    test("parses simple key=value pairs", () => {
      expect(INI.parse("key=value")).toEqual({ key: "value" });
    });

    test("parses key = value with spaces around =", () => {
      expect(INI.parse("key = value")).toEqual({ key: "value" });
    });

    test("parses multiple key-value pairs", () => {
      const result = INI.parse("name = my-app\nversion = 1.0.0");
      expect(result).toEqual({ name: "my-app", version: "1.0.0" });
    });

    test("parses sections as nested objects", () => {
      const input = `
[database]
host = localhost
port = 5432
`;
      expect(INI.parse(input)).toEqual({
        database: {
          host: "localhost",
          port: 5432,
        },
      });
    });

    test("parses top-level keys and sections together", () => {
      const input = `
name = my-app

