1	pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
2	    const object = JSValue.createEmptyObject(globalThis, 2);
3	    object.put(
4	        globalThis,
5	        ZigString.static("parse"),
6	        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
7	    );
8	    object.put(
9	        globalThis,
10	        ZigString.static("stringify"),
11	        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
12	    );
13	    return object;
14	}
15	
16	pub fn parse(
17	    globalThis: *jsc.JSGlobalObject,
18	    callframe: *jsc.CallFrame,
19	) bun.JSError!jsc.JSValue {
20	    const input_value = callframe.argument(0);
21	    if (input_value.isEmptyOrUndefinedOrNull()) {
22	        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
23	    }
24	
25	    var input_slice = try input_value.toSlice(globalThis, bun.default_allocator);
26	    defer input_slice.deinit();
27	
28	    return parseINI(globalThis, input_slice.slice());
29	}
30	
31	fn parseINI(globalThis: *jsc.JSGlobalObject, input: []const u8) bun.JSError!jsc.JSValue {
32	    const result = JSValue.createEmptyObject(globalThis, 0);
33	    result.protect();
34	    defer result.unprotect();
35	
36	    var current_section = result;
37	
38	    var iter = std.mem.splitScalar(u8, input, '\n');
39	    while (iter.next()) |line_raw| {
40	        const line_no_cr = if (line_raw.len > 0 and line_raw[line_raw.len - 1] == '\r')
41	            line_raw[0 .. line_raw.len - 1]
42	        else
43	            line_raw;
44	
45	        const line = bun.strings.trim(line_no_cr, " \t");
46	
47	        // Skip empty lines and comment lines
48	        if (line.len == 0 or line[0] == ';' or line[0] == '#') continue;
49	
50	        // Section header: [section]
51	        if (line[0] == '[') {
52	            const close = std.mem.indexOfScalar(u8, line, ']') orelse continue;
53	            const section_name = bun.strings.trim(line[1..close], " \t");
54	            if (section_name.len == 0) continue;
55	
56	            // Check if section already exists on the root object
57	            var name_str = bun.String.createUTF8(section_name);
58	            defer name_str.deref();
59	
60	            const existing = result.getWithString(globalThis, &name_str);
61	            if (existing != .zero and existing != .js_undefined and existing.isObject()) {
62	                current_section = existing;
63	            } else {
64	                const section_obj = JSValue.createEmptyObject(globalThis, 0);
65	                section_obj.protect();
66	                defer section_obj.unprotect();
67	                try result.putMayBeIndex(globalThis, &name_str, section_obj);
68	                current_section = section_obj;
69	            }
70	            continue;
71	        }
72	
73	        // Key=value pair
74	        const eq_idx = std.mem.indexOfScalar(u8, line, '=');
75	        const key_raw = if (eq_idx) |idx| bun.strings.trim(line[0..idx], " \t") else line;
76	        if (key_raw.len == 0) continue;
77	
78	        const value_js = if (eq_idx) |idx| blk: {
79	            if (idx + 1 < line.len) {
80	                const val_raw = bun.strings.trim(line[idx + 1 ..], " \t");
81	                break :blk parseValue(globalThis, val_raw);
82	            }
83	            // key= with nothing after means empty string
84	            break :blk bun.String.createUTF8ForJS(globalThis, "") catch return .js_undefined;
85	        } else
86	            // key with no = means true
87	            JSValue.jsBoolean(true);
88	
89	        var key_str = bun.String.createUTF8(key_raw);
90	        defer key_str.deref();
91	        try current_section.putMayBeIndex(globalThis, &key_str, value_js);
92	    }
93	
94	    return result;
95	}
96	
97	fn parseValue(globalThis: *jsc.JSGlobalObject, raw: []const u8) jsc.JSValue {
98	    if (raw.len == 0) {
99	        return bun.String.createUTF8ForJS(globalThis, "") catch return .js_undefined;
100	    }
101	
102	    // Handle inline comments: strip text after unquoted ; or #
103	    const effective = stripInlineComment(raw);
104	
105	    // Handle quoted strings (single or double quotes)
106	    if (effective.len >= 2) {
107	        if ((effective[0] == '"' and effective[effective.len - 1] == '"') or
108	            (effective[0] == '\'' and effective[effective.len - 1] == '\''))
109	        {
110	            const inner = effective[1 .. effective.len - 1];
111	            return bun.String.createUTF8ForJS(globalThis, inner) catch return .js_undefined;
112	        }
113	    }
114	
115	    // Boolean values
116	    if (bun.strings.eqlCaseInsensitiveASCII(effective, "true", true))
117	        return JSValue.jsBoolean(true);
118	    if (bun.strings.eqlCaseInsensitiveASCII(effective, "false", true))
119	        return JSValue.jsBoolean(false);
120	
121	    // Null
122	    if (bun.strings.eqlCaseInsensitiveASCII(effective, "null", true))
123	        return .null;
124	
125	    // Try to parse as number
126	    if (parseNumber(effective)) |num| {
127	        return JSValue.jsNumber(num);
128	    }
129	
130	    // Default: string value
131	    return bun.String.createUTF8ForJS(globalThis, effective) catch return .js_undefined;
132	}
133	
134	fn stripInlineComment(raw: []const u8) []const u8 {
135	    // Don't strip from quoted strings
136	    if (raw.len >= 2 and (raw[0] == '"' or raw[0] == '\'')) return raw;
137	
138	    var i: usize = 0;
139	    while (i < raw.len) : (i += 1) {
140	        if (raw[i] == ';' or raw[i] == '#') {
141	            // Only treat as comment if preceded by whitespace (or at start)
142	            if (i == 0 or raw[i - 1] == ' ' or raw[i - 1] == '\t') {
143	                return bun.strings.trim(raw[0..i], " \t");
144	            }
145	        }
146	    }
147	    return raw;
148	}
149	
150	fn parseNumber(s: []const u8) ?f64 {
151	    if (s.len == 0) return null;
152	
153	    // Check for hex
154	    if (s.len > 2 and s[0] == '0' and (s[1] == 'x' or s[1] == 'X')) {
155	        var val: u64 = 0;
156	        for (s[2..]) |c| {
157	            const digit: u64 = switch (c) {
158	                '0'...'9' => c - '0',
159	                'a'...'f' => c - 'a' + 10,
160	                'A'...'F' => c - 'A' + 10,
161	                else => return null,
162	            };
163	            val = val *% 16 +% digit;
164	        }
165	        return @floatFromInt(val);
166	    }
167	
168	    // Parse as float
169	    return std.fmt.parseFloat(f64, s) catch return null;
170	}
171	
172	pub fn stringify(
173	    globalThis: *jsc.JSGlobalObject,
174	    callframe: *jsc.CallFrame,
175	) bun.JSError!jsc.JSValue {
176	    const value = callframe.argument(0);
177	
178	    if (value.isEmptyOrUndefinedOrNull()) {
179	        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
180	    }
181	
182	    if (!value.isObject()) {
183	        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
184	    }
185	
186	    var builder: wtf.StringBuilder = .init();
187	    defer builder.deinit();
188	
189	    // First pass: emit top-level key-value pairs (non-object values)
190	    var has_top_level = false;
191	    {
192	        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
193	            globalThis,
194	            try value.toObject(globalThis),
195	        );
196	        defer iter.deinit();
197	
198	        while (try iter.next()) |prop_name| {
199	            const prop_value = iter.value;
200	            // Skip nested objects (they become sections)
201	            if (prop_value.isObject() and !prop_value.isNull() and !prop_value.isArray()) continue;
202	
203	            has_top_level = true;
204	            appendKey(&builder, prop_name);
205	            builder.append(.latin1, " = ");
206	            try appendValue(&builder, globalThis, prop_value);
207	            builder.append(.lchar, '\n');
208	        }
209	    }
210	
211	    // Second pass: emit sections for nested objects
212	    {
213	        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
214	            globalThis,
215	            try value.toObject(globalThis),
216	        );
217	        defer iter.deinit();
218	
219	        var first_section = true;
220	        while (try iter.next()) |prop_name| {
221	            const prop_value = iter.value;
222	            if (!prop_value.isObject() or prop_value.isNull() or prop_value.isArray()) continue;
223	
224	            // Add blank line before sections
225	            if (!first_section or has_top_level) {
226	                builder.append(.lchar, '\n');
227	            }
228	            first_section = false;
229	
230	            builder.append(.lchar, '[');
231	            appendKey(&builder, prop_name);
232	            builder.append(.latin1, "]\n");
233	
234	            // Emit section properties
235	            var section_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
236	                globalThis,
237	                try prop_value.toObject(globalThis),
238	            );
239	            defer section_iter.deinit();
240	
241	            while (try section_iter.next()) |section_prop_name| {
242	                appendKey(&builder, section_prop_name);
243	                builder.append(.latin1, " = ");
244	                try appendValue(&builder, globalThis, section_iter.value);
245	                builder.append(.lchar, '\n');
246	            }
247	        }
248	    }
249	
250	    return builder.toString(globalThis);
251	}
252	
253	fn appendKey(builder: *wtf.StringBuilder, name: bun.String) void {
254	    builder.append(.string, name);
255	}
256	
257	fn appendValue(builder: *wtf.StringBuilder, globalThis: *jsc.JSGlobalObject, value: jsc.JSValue) bun.JSError!void {
258	    if (value.isNull()) {
259	        builder.append(.latin1, "null");
260	        return;
261	    }
262	
263	    if (value.isBoolean()) {
264	        builder.append(.latin1, if (value.asBoolean()) "true" else "false");
265	        return;
266	    }
267	
268	    if (value.isNumber()) {
269	        if (value.isInt32()) {
270	            builder.append(.int, value.asInt32());
271	        } else {
272	            builder.append(.double, value.asNumber());
273	        }
274	        return;
275	    }
276	
277	    if (value.isString()) {
278	        const str = try value.toBunString(globalThis);
279	        defer str.deref();
280	        // Check if the string needs quoting
281	        if (needsQuoting(str)) {
282	            builder.append(.lchar, '"');
283	            appendEscapedString(builder, str);
284	            builder.append(.lchar, '"');
285	        } else {
286	            builder.append(.string, str);
287	        }
288	        return;
289	    }
290	
291	    if (value.isArray()) {
292	        // Arrays are not natively supported in INI, stringify as comma-separated
293	        var arr_iter = try value.arrayIterator(globalThis);
294	        var first = true;
295	        while (try arr_iter.next()) |item| {
296	            if (!first) builder.append(.latin1, ", ");
297	            first = false;
298	            try appendValue(builder, globalThis, item);
299	        }
300	        return;
301	    }
302	
303	    // For other types, convert to string
304	    const str = try value.toBunString(globalThis);
305	    defer str.deref();
306	    builder.append(.string, str);
307	}
308	
309	fn appendEscapedString(builder: *wtf.StringBuilder, str: bun.String) void {
310	    for (0..str.length()) |i| {
311	        const c = str.charAt(i);
312	        switch (c) {
313	            '\\' => builder.append(.latin1, "\\\\"),
314	            '"' => builder.append(.latin1, "\\\""),
315	            '\n' => builder.append(.latin1, "\\n"),
316	            '\r' => builder.append(.latin1, "\\r"),
317	            '\t' => builder.append(.latin1, "\\t"),
318	            else => builder.append(.uchar, c),
319	        }
320	    }
321	}
322	
323	fn needsQuoting(str: bun.String) bool {
324	    const len = str.length();
325	    if (len == 0) return true;
326	
327	    // Check if first or last char is whitespace
328	    const first = str.charAt(0);
329	    if (first == ' ' or first == '\t') return true;
330	    const last = str.charAt(len - 1);
331	    if (last == ' ' or last == '\t') return true;
332	
333	    for (0..len) |i| {
334	        const c = str.charAt(i);
335	        switch (c) {
336	            ';', '#', '=', '"', '\'', '\n', '\r', '\t', '\\' => return true,
337	            else => {},
338	        }
339	    }
340	
341	    return false;
342	}
